select count(distinct d.delivery_id) from scm_delivery d
where (d.del_flag is null or d.del_flag = '' or d.del_flag = '0')
  and (
    d.zs_order_id = #{zsOrderId}
    or exists (
        select 1 from scm_delivery_detail dd
        inner join zs_tp_order_detail l on l.id = dd.zs_order_detail_id
            and (l.del_flag is null or l.del_flag = '' or l.del_flag = '0')
        where dd.delivery_id = d.delivery_id
          and l.order_id = #{zsOrderId}
          and (dd.del_flag is null or dd.del_flag = '' or dd.del_flag = '0')
    )
    or exists (
        select 1 from zs_tp_order_detail_delivery_rel r
        where r.order_id = #{zsOrderId}
          and r.delivery_id = cast(d.delivery_id as char)
    )
  )

